import React, { useState, useCallback, useEffect } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import { reportPageLabels } from '../../../constants/reportPageLabels';
import { MONTH_OPTIONS, yearOptions } from '../../../constants/voucher';

const labels = reportPageLabels.soTongHop;
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const SoTongHopPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [rows, setRows] = useState<Record<string, unknown>[]>([]);
  const [loading, setLoading] = useState(false);

  const fromDate = `${year}-${month.padStart(2, '0')}-01`;
  const lastDay = new Date(Number(year), Number(month), 0).getDate();
  const toDate = `${year}-${month.padStart(2, '0')}-${lastDay}`;

  const handleLoad = useCallback(() => {
    setLoading(true);
    ktService.getAccountSummary({ fromDate, toDate })
      .then(data => setRows(data as Record<string, unknown>[]))
      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, labels.loadError), type: 'error' })))
      .finally(() => setLoading(false));
  }, [fromDate, toDate, dispatch]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) handleLoad(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [handleLoad]);

  return (
    <div className={erp.page}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-table" /> {labels.title}</h1></div>
      </div>
      <div className={erp.filtersBar} data-testid={`erp-so-tong-hop-filters`}>
        <Select value={month} onChange={e => setMonth(e.target.value)} options={MONTH_OPTIONS} />
        <Select value={year} onChange={e => setYear(e.target.value)} options={yearOptions()} />
        <Button variant="primary" onClick={handleLoad} loading={loading}>{labels.reload}</Button>
        <ListSearchRefreshButtons testIdPrefix="erp-so-tong-hop" onSearch={handleLoad} onRefresh={handleLoad} showSearch={false} />
      </div>
      <div className={erp.tableCard}>
        {loading ? <div className={erp.loading}>{labels.loading}</div> : rows.length === 0 ? <div className={erp.empty}>{labels.empty}</div> : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead><tr><th>{labels.colAccount}</th><th>{labels.colName}</th><th className={erp.colRight}>{labels.colDebit}</th><th className={erp.colRight}>{labels.colCredit}</th></tr></thead>
              <tbody>{rows.map((r, i) => (
                <tr key={i}>
                  <td><code>{String(r.accountCode ?? r.code ?? '')}</code></td>
                  <td>{String(r.accountName ?? r.name ?? '')}</td>
                  <td className={erp.colRight}>{formatVnd(Number(r.debitAmount ?? r.periodDebit ?? 0))}</td>
                  <td className={erp.colRight}>{formatVnd(Number(r.creditAmount ?? r.periodCredit ?? 0))}</td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default SoTongHopPage;
